/** * 제조매출원가 > 기준정보 이월 (TAB010005) */
<template>
  <div>
    <div class="search_box">
      <b-row class="search_area">
        <b-col cols="1" class="period">
          <div class="form-floating me-1">
            <date-picker label="기준월" mode="month" v-model="params.yyyymm" />
            <label for="floatingSelect" class="select">기준월</label>
          </div>
        </b-col>
        <b-col cols="2" class="ms-3">
          <div class="form-floating">
            <input autocomplete="off" type="text" class="form-control label-60" id="floating" placeholder="Site" v-model="params.site" :disabled="true" />
            <label for="floating">사업장</label>
          </div>
        </b-col>
      </b-row>
      <div class="btn_area">
        <b-button v-show="!isClosedMonth" @click="executeClick"><span class="ico_search"></span>실행</b-button>
      </div>
    </div>
     <div 
      class="log-display"
      contenteditable="false"
      v-html="formattedLog" >
      </div>
      <!--h1 style="font-size: 100%; color: blue; font-weight: bold;">[ 경비집계 실행결과 ]</h1>
      <textarea 
        v-model="resultMessage" 
        rows="25" 
        cols="200"
        placeholder="SQL 쿼리가 여기에 표시됩니다"
      ></textarea-->
    <!--div class="grid_box search_onerow">
      <div class="left_box">
        <div class="btn_wrap ms-auto">
          <b-button class="second" @click="excelBtnClick">엑셀</b-button>
        </div>
      </div>
      <div class="grid-border-none">
        <RealGrid ref="expenAmtGrid" :uid="'expenAmtGrid'" :step="'1'" :rows="expenAmtGridRows" style="height: 100%" />
      </div>
    </div>
    <CmDialog1 ref="cmDialog1C00008002" /-->
  </div>
</template>

<script>
import { useUserAuthInfo } from '@store/auth/userAuthInfo';
import { useC0001001 } from '@web/store/C0001001.js';

export default {
  props: {},
  components: {},
  setup() {
    const srchInfo = useC0001001();
    const userAuthInfo = useUserAuthInfo();
    return { 
	  srchInfo,
      userAuthInfo 
    };
  },
  data() {
    return {
      expenAmtGrid: null,
      expenAmtGridRows: [],
      params: {
        yyyymm: '',
        site: 'HQ',
      },
      siteMap: {
        본사: 'HQ', //DB map
        VINA: 'VN', //DB map
        HQ: 'HQ', //DB map
        VN: 'VN', //DB map
      },
      isProcessing: false,
      resultMessage: '',
      isClosedMonth: false,
    };
  },
  watch: { 
    'params.yyyymm': async function(newVal) {
      if (newVal) {
        this.onDateChange();
        await this.checkClosingMonth();
      } else {
        this.isClosedMonth = false;
      }
    },
    'srchInfo.yyyymm': {
      handler(newVal) {
        if (newVal) {
          this.params.yyyymm = newVal;
        }
      }
     },
    userAuthInfo: {
      handler(newVal) {
        if (newVal.curProdCtg) {
          this.params.site = newVal.curProdCtg === 'VN' ? 'VINA' : '본사';
          //if (this.$refs.expenAmtGrid != null) {
            this.initialize();
            //this.executeClick();
          //}
        }
      },
      // deep: true,
      // immediate: true,
    },
  },
  computed: {
    formattedLog() {
      // ERROR를 빨간색으로 강조 - 대괄호 이스케이프 및 여러 줄 처리
      // 각 줄로 분할
      const lines = this.resultMessage.split('\n');
      // 각 줄을检查하여 [ERROR]로 시작하면 span으로 감싸기
      const formattedLines = lines.map(line => {
        if (line.startsWith('[ERROR]')) {
          return `<span class="error-text">${line}</span>`;
        }
        else if (line.startsWith('[START]')) {
          return `<span class="start-text">${line}</span>`;
        }
        else if (line.startsWith('[FINISH]')) {
          return `<span class="finish-text">${line}</span>`;
        }
        return line;
      });
      // 다시 합치기
      return formattedLines.join('<br>');
    },
    // gridView() {
    //   return this.$refs.expenAmtGrid.getGridView();
    // },
    // gridDataProvider() {
    //   return this.$refs.expenAmtGrid.getGridDataProvider();
    // },
  },
  created() {
    this.initialize();
    this.checkClosingMonth();
    //this.initializeGrid();
  },
  mounted() {},
  beforeUnmount() {},
  methods: {
    initialize() {
      //var current = new Date();
      this.params.yyyymm = this.srchInfo.yyyymm;//`${current.getFullYear()}-${(current.getMonth() + 1).toString().padStart(2, '0')}`;
      this.params.site = this.userAuthInfo.curProdCtg === 'VN' ? 'VINA' : '본사';      
      this.resultMessage = `실행 버튼을 클릭하면 ${this.params.yyyymm}월 ${this.params.site} 기준정보 데이터 이월 실행 합니다`;
    },
    initializeGrid() {
      //this.expenAmtGrid = _.cloneDeep(gridField);
    },
    onDateChange() {
      this.resultMessage = `실행 버튼을 클릭하면 ${this.params.yyyymm}월 ${this.params.site} 기준정보 데이터 이월 실행 합니다`;
      this.srchInfo.setSearchInfo({ yyyymm: this.params.yyyymm });
    },
    async checkClosingMonth() {
      const yyyymm = this.params.yyyymm
        ? this.params.yyyymm.replaceAll('-', '')
        : null;

      if (!yyyymm) {
        this.isClosedMonth = false;
        return;
      }

      try {
        const res = await this.$axios.get('/api/common/closing-month/check', {
          params: { yyyymm },
        });

        this.isClosedMonth =
          res?.data?.isClosed === true || res?.data?.isClosed === 'Y';

      } catch (e) {
        console.error('마감월 조회 실패', e);
        this.isClosedMonth = false;
      }
    },
    async getDataList() {
      //this.gridView.commit();

      let params = {
        yyyymm: this.params.yyyymm != null ? this.params.yyyymm.replaceAll('-', '') : null,
        site: this.params.site != null ? this.siteMap[this.params.site] : null,
        selcode: 'ACTUAL', // 실제 데이터
      };

      let param = {
        menuId: 'c0001004',
        queryId: 'TAB010005_Sch1',
        queryParams: params,
        target: null,
      };
      let resp = await this.$axios.api.search(param);
      console.log('응답 데이터:', JSON.stringify(resp,null,2));
      console.log('응답 데이터:', resp);
      console.log('응답 데이터:', resp[0].retmessage);
      // OUTPUT 매개변수로 받은 메시지 표시
      if (resp && resp[0].retmessage) {
        this.resultMessage = resp[0].retmessage;
          // this.$message({
          //     message: resp.data.retmessage,
          //     type: 'info',
          //     duration: 5000
          // });
      }
    },
    executeClick() {
      this.getDataList();
    },
  } 
};
</script>
<style scoped>
.log-display {
  width: 100%;
  min-height: 200px;
  max-height: 400px;
  overflow-y: auto;
  border: 1px solid #ccc;
  border-radius: 4px;
  padding: 10px;
  font-family: 'Courier New', monospace;
  font-size: 13px;
  line-height: 1.4;
  white-space: pre-wrap;
  background-color: #f8f9fa;
}

.log-display ::v-deep .error-text { 
  color: rgb(209, 70, 70);
  font-weight: bold;
}

.log-display ::v-deep .start-text { 
  color: #0056b3;
  font-weight: bold;
}

.log-display ::v-deep .finish-text { 
  color: #28a745;
  font-weight: bold;
}
</style>
